sys_script_include.script:
var dm_import = Class.create();
dm_import.prototype = {

    initialize: function() {
        // Automatically get the current instance URL
        this.instanceUrl = gs.getProperty('glide.servlet.uri');
        this.username = '';
        this.password = '';

        // Grab the active admin credentials to authenticate the Ghost Browser upload
        var connGr = new GlideRecord('x_1862238_tracenow_connections');
        connGr.addQuery('status', 'Active');
        connGr.query();
        if (connGr.next()) {
            var customUrl = connGr.getValue('source_instance_url');
            if (customUrl) {
                this.instanceUrl = customUrl.endsWith('/') ? customUrl : customUrl + '/';
            }
            this.username = connGr.getValue('username');
            this.password = connGr.password.getDecryptedValue() || connGr.getValue('password');
        }
    },

    processXML: function(xmlString) {
        if (!this.username) {
            return { error: "TraceNow requires an Active Connection with admin credentials to bypass the scoped sandbox.", count: 0 };
        }
        if (!xmlString || xmlString.indexOf('<unload') === -1) {
            return { error: "Invalid XML format.", count: 0 };
        }

        try {
            // 1. Manually construct a multipart/form-data payload to trick the native XML processor
            var boundary = "----WebKitFormBoundaryTraceNow" + gs.generateGUID().replace(/-/g, '');
            var body = "";

            body += "--" + boundary + "\r\n";
            body += 'Content-Disposition: form-data; name="sysparm_target"\r\n\r\n';
            body += 'sys_import\r\n';

            body += "--" + boundary + "\r\n";
            body += 'Content-Disposition: form-data; name="sysparm_action"\r\n\r\n';
            body += 'sys_import\r\n';

            body += "--" + boundary + "\r\n";
            body += 'Content-Disposition: form-data; name="sys_import"; filename="import.xml"\r\n';
            body += 'Content-Type: text/xml\r\n\r\n';
            body += xmlString + "\r\n";

            body += "--" + boundary + "--\r\n";

            // 2. Execute the REST call directly to the native C++ XML Processor
            var rm = new sn_ws.RESTMessageV2();
            rm.setEndpoint(this.instanceUrl + 'sys_upload.do');
            rm.setHttpMethod('POST');
            rm.setBasicAuth(this.username, this.password);
            rm.setRequestHeader('Content-Type', 'multipart/form-data; boundary=' + boundary);
            rm.setRequestBody(body);

            var response = rm.execute();
            var statusCode = response.getStatusCode();

            // 3. If HTTP 200 OK or 302 Redirect, the system successfully absorbed the payload
            if (statusCode === 200 || statusCode === 302) {
                // Estimate the imported count by finding the number of sys_ids in the payload
                var recordCount = (xmlString.match(/<sys_id>/g) || []).length;
                return { error: "", count: recordCount };
            } else {
                var errorMsg = "Native XML Processor rejected the payload (HTTP " + statusCode + "). Ensure the Connection User has the 'admin' role.";
                return { error: errorMsg, count: 0 };
            }
        } catch (ex) {
            return { error: "Ghost Browser Error: " + String(ex.message), count: 0 };
        }
    },

    type: 'dm_import'
};
